ALGORITHM BinarySearch(arr, low, high, key)
BEGIN
  WHILE low <= high DO
    mid = (low + high) / 2
    IF arr[mid] == key THEN
      RETURN mid
    ELSE IF arr[mid] < key THEN
      low = mid + 1
    ELSE
      high = mid - 1
    END IF
  END WHILE
  RETURN -1
END

