ALGORITHM SortedInsert(arr, n, key)
BEGIN
  IF n == MAX_SIZE THEN
    RETURN -1  // Array full
  END IF

  // Find position where key should be inserted
  i = n - 1
  WHILE i >= 0 AND arr[i] > key DO
    arr[i + 1] = arr[i]
    i = i - 1
  END WHILE

  arr[i + 1] = key
  RETURN i + 1
END

